import{_ as l,c as i,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Getting Started: Installation & Setup | OpenSkills","description":"Learn how to install and configure OpenSkills for AI coding agents. Complete the setup in 10-15 minutes, from tool installation to skill synchronization.","frontmatter":{"title":"Getting Started: Installation & Setup | OpenSkills","sidebarTitle":"Getting Started","subtitle":"Getting Started: Installation & Setup","order":1,"description":"Learn how to install and configure OpenSkills for AI coding agents. Complete the setup in 10-15 minutes, from tool installation to skill synchronization."},"headers":[],"relativePath":"numman-ali/openskills/start/index.md","filePath":"numman-ali/openskills/start/index.md"}'),s={name:"numman-ali/openskills/start/index.md"};function n(o,e,r,d,h,c){return t(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This section helps you get started with OpenSkills. From installing the tool to enabling AI agents to use skills, it takes just 10-15 minutes.</p><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to &quot;Learning Path&quot;">​</a></h2><p>We recommend following this order:</p><h3 id="_1-quick-start" tabindex="-1">1. <a href="./quick-start/">Quick Start</a> <a class="header-anchor" href="#_1-quick-start" aria-label="Permalink to &quot;1. [Quick Start](./quick-start/)&quot;">​</a></h3><p>Complete tool installation, skill installation, and sync in under 5 minutes, and experience the core value of OpenSkills.</p><ul><li>Install OpenSkills tool</li><li>Install skills from the official Anthropic repository</li><li>Sync skills to AGENTS.md</li><li>Verify that AI agents can use skills</li></ul><h3 id="_2-what-is-openskills" tabindex="-1">2. <a href="./what-is-openskills/">What is OpenSkills?</a> <a class="header-anchor" href="#_2-what-is-openskills" aria-label="Permalink to &quot;2. [What is OpenSkills?](./what-is-openskills/)&quot;">​</a></h3><p>Understand the core concepts and working principles of OpenSkills.</p><ul><li>The relationship between OpenSkills and Claude Code</li><li>Unified skill format, progressive loading, multi-agent support</li><li>When to use OpenSkills instead of the built-in skill system</li></ul><h3 id="_3-installation-guide" tabindex="-1">3. <a href="./installation/">Installation Guide</a> <a class="header-anchor" href="#_3-installation-guide" aria-label="Permalink to &quot;3. [Installation Guide](./installation/)&quot;">​</a></h3><p>Detailed installation steps and environment configuration.</p><ul><li>Node.js and Git environment check</li><li>npx temporary usage vs global installation</li><li>Troubleshooting common installation issues</li></ul><h3 id="_4-install-your-first-skill" tabindex="-1">4. <a href="./first-skill/">Install Your First Skill</a> <a class="header-anchor" href="#_4-install-your-first-skill" aria-label="Permalink to &quot;4. [Install Your First Skill](./first-skill/)&quot;">​</a></h3><p>Install skills from the official Anthropic repository and experience interactive selection.</p><ul><li>Use the <code>openskills install</code> command</li><li>Interactively select the skills you need</li><li>Understand the skill directory structure (.claude/skills/)</li></ul><h3 id="_5-sync-skills-to-agents-md" tabindex="-1">5. <a href="./sync-to-agents/">Sync Skills to AGENTS.md</a> <a class="header-anchor" href="#_5-sync-skills-to-agents-md" aria-label="Permalink to &quot;5. [Sync Skills to AGENTS.md](./sync-to-agents/)&quot;">​</a></h3><p>Generate the AGENTS.md file to let AI agents know about available skills.</p><ul><li>Use the <code>openskills sync</code> command</li><li>Understand the XML format of AGENTS.md</li><li>Select skills to sync to control context size</li></ul><h3 id="_6-reading-skills" tabindex="-1">6. <a href="./read-skills/">Reading Skills</a> <a class="header-anchor" href="#_6-reading-skills" aria-label="Permalink to &quot;6. [Reading Skills](./read-skills/)&quot;">​</a></h3><p>Understand how AI agents load skill content.</p><ul><li>Use the <code>openskills read</code> command</li><li>The 4-level priority order for skill lookup</li><li>Read multiple skills at once</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before you start, please confirm:</p><ul><li>You have installed <a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> 20.6.0 or higher</li><li>You have installed <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> (for installing skills from GitHub)</li><li>You have installed at least one AI coding agent (Claude Code, Cursor, Windsurf, Aider, etc.)</li></ul><div class="tip custom-block"><p class="custom-block-title">Quick Environment Check</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # Should show v20.6.0 or higher</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Should show git version x.x.x</span></span></code></pre></div></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this section, you can continue learning:</p><ul><li><a href="./../platforms/cli-commands/">Command Reference</a>: Learn more about all commands and parameters</li><li><a href="./../platforms/install-sources/">Installation Sources</a>: Learn how to install skills from GitHub, local paths, and private repositories</li><li><a href="./../advanced/create-skills/">Create Custom Skills</a>: Build your own skills</li></ul>`,29)])])}const k=l(s,[["render",n]]);export{u as __pageData,k as default};
